/// External session id used to route ACP traffic. This is the
/// [Agent Client Protocol](https://agentclientprotocol.com) native `SessionId`
/// (a UUID-ish string), generated by the bridge on `new_session` and handed
/// back to clients. Distinct from [`AgentSessionId`], which is the underlying
/// agent-subprocess session.
pub use agent_client_protocol::SessionId;

/// ACP-native prompt content. A prompt is a sequence of these blocks (text,
/// image, audio, resource link, embedded resource). Re-exported so IM adapters
/// build prompts in the protocol's own vocabulary without depending on the
/// `agent_client_protocol` crate directly.
pub use agent_client_protocol::{ContentBlock, ResourceLink, TextContent};

/// Best-effort flatten of ACP content blocks into a single plain-text string.
/// Used by non-ACP backends (which only accept text) and for logging.
pub fn content_to_text(content: &[ContentBlock]) -> String {
    let mut parts: Vec<String> = Vec::new();
    for block in content {
        match block {
            ContentBlock::Text(t) => parts.push(t.text.clone()),
            ContentBlock::ResourceLink(r) => {
                parts.push(format!("[{}]({})", r.name, r.uri));
            }
            ContentBlock::Image(_) => parts.push("[image]".to_string()),
            ContentBlock::Audio(_) => parts.push("[audio]".to_string()),
            ContentBlock::Resource(_) => parts.push("[resource]".to_string()),
            _ => {}
        }
    }
    parts.join("\n")
}

/// Build a single-text-block prompt (the common case).
pub fn text_prompt(text: impl Into<String>) -> Vec<ContentBlock> {
    vec![ContentBlock::Text(TextContent::new(text.into()))]
}

/// Bridge-level operations. InputSources produce these from platform-specific
/// interactions (text commands, button clicks, CLI flags, JSON messages).
/// Bridge only receives and executes them — it never parses raw text.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub enum Command {
    /// `/cd <path>` — with explicit path
    Cd(PathBuf),
    /// `/cd` — no argument, trigger interactive directory listing
    CdInteractive,
    /// `/new`
    New,
    /// `/close [#N]` — close (destroy) a session. `/stop` is an alias.
    Close(Option<u32>),
    /// `/cancel` — cancel the running prompt but keep the session alive.
    Cancel,
    /// `/agent [name]` — switch agent backend, or list available agents.
    Agent(Option<String>),
    /// `/sessions` — list active sessions.
    Sessions,
    /// `/yolo`
    Yolo,
    /// `/safe`
    Safe,
    /// `/help` or `/?`
    Help,
    /// Bare-token affirmative: `y`, `yes`, `是`, `好`.
    YesToken,
    /// Bare-token negative: `n`, `no`, `否`, `不`.
    NoToken,
    /// Session-level approval: `s`, `session`, `会话`.
    SessionApprove,
    /// Anything else — including unknown slash-commands which are forwarded
    /// to the agent as-is.
    Plain(String),
}

/// A project the agent can be directed to clone and develop.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub struct Project {
    pub name: String,
    pub git_url: String,
}

/// Stable identifier for an agent session, returned by AgentBackend::new_session.
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct AgentSessionId(pub String);

impl AgentSessionId {
    pub fn new(s: impl Into<String>) -> Self {
        Self(s.into())
    }
    pub fn as_str(&self) -> &str {
        &self.0
    }
}

impl std::fmt::Display for AgentSessionId {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(&self.0)
    }
}

/// Identifies the IM-side counterpart of a conversation.
///
/// `opaque` carries platform-specific context (e.g. iLink's `context_token`)
/// that the bridge doesn't interpret but the IM adapter needs back when sending.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PeerRef {
    pub user_id: String,
    pub group_id: Option<String>,
    pub opaque: serde_json::Value,
}

/// Pre-parsed inbound message from any source (IM, ACP, CLI).
/// Sources parse their platform-specific format internally and produce this
/// bridge-level type. Bridge never sees raw IM message kinds.
#[derive(Debug, Clone)]
pub struct SourceMessage {
    pub peer: PeerRef,
    pub payload: InboundPayload,
    pub received_at: SystemTime,
}

/// One frame of progress from the agent during a prompt.
///
/// Streaming content (text, tool calls, plans, mode changes, session info) is
/// carried as the ACP-native [`SessionUpdate`] inside the `Session` variant.
/// Only agentline-specific control events get their own variants.
#[derive(Debug, Clone)]
pub enum AgentUpdate {
    /// ACP session update — streaming content forwarded as-is.
    Session(SessionUpdate),
    /// Agent needs user permission for an action.
    PermissionRequest {
        id: String,
        what: String,
        danger: PermissionDanger,
        tool_kind: ToolKind,
    },
    /// Agent is asking the user a question (ACP elicitation).
    ElicitInput {
        id: String,
        prompt: String,
        schema: Option<ElicitationSchema>,
    },
    Done,
    Error(String),
}

