// ── New types for the InputSource architecture ──────────────────────────

/// Parsed inbound payload: either a command or user content.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum InboundPayload {
    /// A command recognized by the InputSource (e.g. /yolo, button click, CLI flag).
    Command(Command),
    /// User content to be sent to the agent.
    Content(UserContent),
}

/// Composite user message: text + zero or more attachments.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct UserContent {
    pub text: Option<String>,
    pub attachments: Vec<Attachment>,
}

impl UserContent {
    pub fn text(s: impl Into<String>) -> Self {
        Self {
            text: Some(s.into()),
            attachments: Vec::new(),
        }
    }

    pub fn is_empty(&self) -> bool {
        self.text.as_ref().is_none_or(|t| t.is_empty()) && self.attachments.is_empty()
    }

    pub fn to_prompt_text(&self) -> String {
        let mut parts = Vec::new();
        if let Some(ref text) = self.text {
            parts.push(text.clone());
        }
        for att in &self.attachments {
            match att.kind {
                AttachmentKind::Image => {
                    parts.push(format!("![image]({})", att.local_path.display()));
                }
                AttachmentKind::Voice => {
                    if let Some(ref transcript) = att.transcript {
                        parts.push(transcript.clone());
                    } else {
                        parts.push(format!("[voice]({})", att.local_path.display()));
                    }
                }
                AttachmentKind::File => {
                    let name = att.name.as_deref().unwrap_or("file");
                    parts.push(format!("[file: {}]({})", name, att.local_path.display()));
                }
                AttachmentKind::Video => {
                    parts.push(format!("[video]({})", att.local_path.display()));
                }
            }
        }
        parts.join("\n")
    }

    pub fn to_content_blocks(&self) -> Vec<ContentBlock> {
        let mut blocks = Vec::new();
        if let Some(ref text) = self.text
            && !text.is_empty()
        {
            blocks.push(ContentBlock::Text(TextContent::new(text.clone())));
        }
        for att in &self.attachments {
            let uri = format!("file://{}", att.local_path.display());
            let name = match att.kind {
                AttachmentKind::Image => att.name.clone().unwrap_or_else(|| "image".into()),
                AttachmentKind::Voice => att.name.clone().unwrap_or_else(|| "voice".into()),
                AttachmentKind::File => att.name.clone().unwrap_or_else(|| "file".into()),
                AttachmentKind::Video => att.name.clone().unwrap_or_else(|| "video".into()),
            };
            blocks.push(ContentBlock::ResourceLink(ResourceLink::new(name, uri)));
            if let Some(ref transcript) = att.transcript {
                blocks.push(ContentBlock::Text(TextContent::new(transcript.clone())));
            }
        }
        if blocks.is_empty() {
            blocks.push(ContentBlock::Text(TextContent::new(String::new())));
        }
        blocks
    }
}

/// A single attachment in an inbound message.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Attachment {
    pub kind: AttachmentKind,
    /// Local path (InputSource downloads media before handing off to Bridge).
    pub local_path: PathBuf,
    /// Display name (for files).
    pub name: Option<String>,
    /// Voice-to-text transcript (for voice attachments).
    pub transcript: Option<String>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum AttachmentKind {
    Image,
    Voice,
    File,
    Video,
}

/// Inbound message with routing information (which InputSource it came from).
/// The payload is already parsed by the InputSource's `parse_message`.
#[derive(Debug, Clone)]
pub struct RoutedMessage {
    pub source_id: String,
    pub peer: PeerRef,
    pub payload: InboundPayload,
    pub received_at: std::time::SystemTime,
}

// ── Bridge atomic API result types ───────────────────────────────────

/// Result of `Bridge::set_mode()`.
#[derive(Debug, Clone)]
pub enum ModeResult {
    /// Mode applied to the active session.
    Applied { tag: String },
    /// No active session; mode will apply to the next session created.
    Pending,
    /// No active session (and mode cannot be deferred).
    NoSession,
}

/// Result of `Bridge::set_cwd()`.
#[derive(Debug, Clone)]
pub enum CwdResult {
    /// cwd changed, no session impact.
    Changed,
    /// cwd changed and the active session was closed because cwd differs.
    SessionClosed { tag: String },
    /// Path does not exist.
    NotFound,
    /// Path is not a directory.
    NotADir,
}

/// Result of `Bridge::prompt()`.
#[derive(Debug, Clone)]
pub enum PromptResult {
    /// Prompt dispatched immediately.
    Started,
    /// Another prompt is running; this one was queued.
    Queued { tag: String },
}

/// Result of `Bridge::respond_permission()`.
#[derive(Debug, Clone)]
pub enum PermissionResult {
    /// Permission was answered.
    Answered {
        effective: crate::permission::PermissionResponse,
    },
    /// No pending permission request.
    NoPending,
}

/// Snapshot of the current session for external display.
#[derive(Debug, Clone)]
pub struct SessionInfo {
    pub short_id: u32,
    pub session_id: String,
    pub agent_name: String,
    pub cwd: std::path::PathBuf,
    pub created_at: std::time::SystemTime,
    pub idle_duration: std::time::Duration,
    pub is_yolo: bool,
    pub grant_summary: String,
}

/// Parse user reply into a structured `serde_json::Value` based on the
/// elicitation schema. If schema carries selectable options, numeric input
/// is resolved to the corresponding option value.
pub fn parse_elicit_response(text: &str, schema: Option<&ElicitationSchema>) -> serde_json::Value {
    let text = text.trim();
    let Some(schema) = schema else {
        return serde_json::Value::String(text.to_string());
    };
    let Some((_, prop)) = schema.properties.iter().next() else {
        return serde_json::Value::String(text.to_string());
    };
    match prop {
        ElicitationPropertySchema::String(s) => {
            if let Some(options) = single_select_options(s)
                && let Ok(n) = text.parse::<usize>()
                && n >= 1
                && n <= options.len()
            {
                return serde_json::Value::String(options[n - 1].0.clone());
            }
            serde_json::Value::String(text.to_string())
        }
        ElicitationPropertySchema::Array(ms) => {
            let options = multi_select_options(&ms.items);
            let indices: Vec<usize> = text
                .split(',')
                .filter_map(|s| s.trim().parse::<usize>().ok())
                .collect();
            if !indices.is_empty() && indices.iter().all(|&i| i >= 1 && i <= options.len()) {
                let values: Vec<serde_json::Value> = indices
                    .iter()
                    .map(|&i| serde_json::Value::String(options[i - 1].0.clone()))
                    .collect();
                return serde_json::Value::Array(values);
            }
            serde_json::Value::String(text.to_string())
        }
        ElicitationPropertySchema::Boolean(_) => {
            let lower = text.to_lowercase();
            match lower.as_str() {
                "y" | "yes" | "true" | "是" | "1" => serde_json::Value::Bool(true),
                "n" | "no" | "false" | "否" | "0" => serde_json::Value::Bool(false),
                _ => serde_json::Value::String(text.to_string()),
            }
        }
        ElicitationPropertySchema::Number(_) | ElicitationPropertySchema::Integer(_) => {
            if let Ok(n) = text.parse::<f64>() {
                serde_json::Number::from_f64(n)
                    .map(serde_json::Value::Number)
                    .unwrap_or_else(|| serde_json::Value::String(text.to_string()))
            } else {
                serde_json::Value::String(text.to_string())
            }
        }
        _ => serde_json::Value::String(text.to_string()),
    }
}

/// Extract (value, label) pairs from a single-select string property.
pub fn single_select_options(
    s: &agent_client_protocol::StringPropertySchema,
) -> Option<Vec<(String, String)>> {
    if let Some(ref one_of) = s.one_of {
        let opts: Vec<(String, String)> = one_of
            .iter()
            .map(|o| (o.value.clone(), o.title.clone()))
            .collect();
        if !opts.is_empty() {
            return Some(opts);
        }
    }
    if let Some(ref values) = s.enum_values {
        let opts: Vec<(String, String)> = values.iter().map(|v| (v.clone(), v.clone())).collect();
        if !opts.is_empty() {
            return Some(opts);
        }
    }
    None
}

/// Extract (value, label) pairs from multi-select items.
pub fn multi_select_options(
    items: &agent_client_protocol::MultiSelectItems,
) -> Vec<(String, String)> {
    use agent_client_protocol::MultiSelectItems;
    match items {
        MultiSelectItems::Titled(t) => t
            .options
            .iter()
            .map(|o| (o.value.clone(), o.title.clone()))
            .collect(),
        MultiSelectItems::Untitled(u) => u
            .values
            .iter()
            .map(|v: &String| (v.clone(), v.clone()))
            .collect(),
        _ => Vec::new(),
    }
}
